export const CAREERS = [
  { icon: "🏥", content: { en: { title: "Healthcare & Nursing", salary: "£22K–£50K+" } }, tags: ["NMC", "NHS", "Band 2–7"], steps: { en: ["Start as an HCA (Healthcare Assistant, Band 2–3) — no UK experience or qualifications required. Your employer funds the Care Certificate (15 standards, fully paid). This gets you inside the NHS and earning while you build your registration.", "NHS Refugee Employment Programme: NHS England runs dedicated refugee employment hubs in most regions. These provide fast-track HCA recruitment, mentoring, and a direct pathway to sponsored visa roles. Search 'NHS refugee employment' for your local trust.", "Overseas trained nurses (RN): register with the NMC (Nursing and Midwifery Council). The process takes 6–18 months. Steps: (1) NMC application + identity check, (2) English language test (OET or IELTS Academic 7.0+), (3) Computer-Based Test (CBT) — nursing theory, (4) OSCE (Objective Structured Clinical Examination) — practical assessment at a UK NHS site.", "Many NHS trusts sponsor overseas nurses directly and cover all NMC registration costs, CBT and OSCE fees, and relocation support. Apply to NHS trusts directly via NHS Jobs and state your NMC registration status upfront.", "Allied Health Professions (AHPs) in critical shortage: physiotherapists, occupational therapists, radiographers, paramedics, diagnostic radiographers, and speech and language therapists are all on the UK shortage occupation list. Visa sponsorship is standard.", "Overseas AHPs: register with the HCPC (Health and Care Professions Council) — the UK regulator for 15 AHP roles. Process similar to NMC: application, English test, and sometimes an aptitude test (TURAS in Scotland).", "Pharmacy: GPhC (General Pharmaceutical Council) registers overseas pharmacists. Many community pharmacies sponsor internationally qualified pharmacists — these roles pay £35K–£50K+.", "Doctors (IMGs — International Medical Graduates): register with the GMC (General Medical Council). PLAB 1 and PLAB 2 exams required. Many NHS trusts sponsor IMG doctors directly. Starting grade: FY2 or CT1 depending on experience.", "Salary guide: HCA Band 2–3 £23K–£25K → Staff Nurse Band 5 £29K–£36K → Senior Nurse Band 6 £37K–£43K → Ward Manager Band 7 £43K–£50K+. NHS also provides pension, annual leave (27–33 days), and development support."] }, links: [{ name: "NHS Jobs", url: "https://www.jobs.nhs.uk/" }, { name: "NMC Registration (nurses)", url: "https://www.nmc.org.uk/registration/joining-the-register/" }, { name: "HCPC Registration (AHPs)", url: "https://www.hcpc-uk.org/registration/joining-the-register/" }, { name: "GMC Registration (doctors)", url: "https://www.gmc-uk.org/registration-and-licensing/join-the-register" }, { name: "NHS Refugee Employment", url: "https://www.england.nhs.uk/looking-after-our-people/health-and-wellbeing/refugee-and-asylum-seeker-programme/" }] },
  { icon: "🤝", content: { en: { title: "Social Work & Support Work", salary: "£22K–£45K+" } }, tags: ["HCPC", "Social Work England", "Care Cert"], steps: { en: ["Support Worker is one of the most accessible, high-demand entry roles in the UK — no prior UK experience required. Start within weeks of getting refugee status.", "The Care Certificate (15-standard induction, free from employer) is your entry credential. NHS, care homes, charities, and councils all hire Support Workers immediately.", "Support Worker salary: £22K–£28K. Senior Support Worker: £28K–£35K. Many roles offer shift premiums, overtime, and free training.", "If you have a relevant overseas degree (social sciences, psychology, health, education), you can train as a qualified Social Worker. Social Work England is the UK regulator.", "The ASYE (Assessed and Supported Year in Employment) is a paid first year of practice after qualifying — all employers provide this automatically.", "Qualifying routes: MA Social Work (2 years, funded bursary available), or fast-track Frontline/Step Up programmes for graduates (salaried, competitive).", "High-demand specialisms with better pay: mental health, learning disabilities, children's services (CYPS), domestic abuse support, refugee resettlement (directly relevant).", "Organisations specifically hiring refugees and people with lived experience: Nacro, St Mungo's, Shelter, Mind, Rethink, local councils.", "Overseas social work qualifications: assessed by Social Work England — contact them at socialworkengland.org.uk for your specific route.", "HCPC (Health and Care Professions Council) regulates social workers in some devolved nations — check requirements for Scotland, Wales, Northern Ireland separately."] }, links: [{ name: "Social Work England", url: "https://www.socialworkengland.org.uk/" }, { name: "Frontline (fast-track social work)", url: "https://thefrontline.org.uk/" }, { name: "Step Up to Social Work", url: "https://www.gov.uk/guidance/step-up-to-social-work" }, { name: "NHS Jobs — Support Worker", url: "https://www.jobs.nhs.uk/" }] },
  { icon: "🗣", content: { en: { title: "Translation & Interpreting", salary: "£25K–£60K+" } }, tags: ["CIOL", "NRPSI", "Rare languages"], steps: { en: ["Many languages spoken by refugees in the UK are critically under-supplied: Arabic, Amharic, Tigrinya, Somali, Pashto, Dari, Kurdish (Kurmanji/Sorani), Ukrainian, and Urdu are all in constant demand in hospitals, courts, local authorities, and the asylum system. Your language is a professional qualification.", "Start immediately — no qualification required: Language Line, thebigword, and Capita Translation hire telephone and video interpreters now. You register online, complete an audio assessment, and can be earning within 2–4 weeks. Your language skills are enough to begin.", "NHS interpreting: contact your local NHS trust's interpreter services department directly. The NHS is legally required to provide interpreting for patients and always needs rare language speakers urgently. Some trusts hire staff interpreters (salaried) as well as bank/agency interpreters.", "Court and legal interpreting: the highest-paid work (£35–£65/hr for rare languages). Register with the National Register of Public Service Interpreters (NRPSI) — this unlocks NHS, police, and criminal court bookings. NRPSI membership is essential for public sector work.", "CIOL (Chartered Institute of Linguists): the UK's leading professional body for language professionals. The Diploma in Translation (DipTrans) is the gold-standard qualification for written translators. The IoLET Level 6 Diploma in Public Service Interpreting (DPSI) is the equivalent for spoken interpreters.", "ITI (Institute of Translation and Interpreting): professional membership and a searchable directory. Associate membership is available while building your portfolio. Listed members receive direct agency enquiries.", "Written translation: create a freelance profile on ProZ.com, Translators Cafe, and the ITI directory. Rare language pairs (e.g. English–Amharic, English–Tigrinya, English–Somali) command £0.10–£0.20 per word — significantly above average market rates.", "Premium translation niches for people with professional backgrounds: technical translation (engineering manuals, contracts), legal translation (court documents, immigration papers), medical translation (discharge summaries, consent forms). These pay 30–50% above general rates.", "Long-term: many experienced translators and interpreters establish their own Language Service Provider (LSP) business. With rare language pairs and professional experience, this is a realistic and profitable path."] }, links: [{ name: "NRPSI (public service register)", url: "https://www.nrpsi.org.uk" }, { name: "CIOL (Chartered Institute of Linguists)", url: "https://www.ciol.org.uk" }, { name: "ITI (Institute of Translation)", url: "https://www.iti.org.uk" }, { name: "Language Line — become an interpreter", url: "https://www.languageline.com/uk/interpreters/" }] },
  { icon: "💻", content: { en: { title: "Technology & Digital", salary: "£28K–£90K+" } }, tags: ["Bootcamps", "Apprenticeships", "Remote-friendly"], steps: { en: ["Start for free: Google Career Certificates cover IT Support, Data Analytics, Cybersecurity, UX Design, and Project Management — all free with financial aid. Each takes 3–6 months and is recognised by UK employers.", "Code Your Future: the UK's leading free coding bootcamp specifically for refugees and people from disadvantaged backgrounds. Full-stack web development, fully funded. Covers living costs during the programme.", "Generation UK: free skills training programmes (IT support, junior developer, data technician) with employer partners. Specifically targets people who face barriers to employment.", "Skills Bootcamps (gov.uk): fully funded by government — AWS, Azure, cybersecurity, data science, full-stack development. 16 weeks, guaranteed employer interview on completion.", "BCS (Chartered Institute for IT): the UK's professional IT body. Professional membership, certification pathways (CITP), and a refugees-in-tech support network. Essential for building credibility with UK employers.", "Entry-level roles to target: IT Support Analyst, Junior Developer, Data Analyst, QA Tester, Junior Cyber Analyst. Apprenticeship Degree routes at BT, Amazon, Accenture, Fujitsu let you earn £20K–£25K while qualifying.", "NHS Digital, GDS (Government Digital Service), DWP Digital, and HMRC Digital all run active refugee hiring schemes and social value employment programmes. These are among the most accessible tech employers for new arrivals.", "Build a portfolio on GitHub. Even 2–3 small projects demonstrate practical skills. Recruiters look at GitHub profiles for junior developer roles — a portfolio beats a CV.", "Salary progression: IT Support £22K–£30K → Junior Dev/Analyst £28K–£38K → Mid £38K–£55K → Senior/Lead £55K–£90K+. Remote and hybrid roles are the norm — you are not tied to one city."] }, links: [{ name: "Google Career Certificates", url: "https://grow.google/certificates/" }, { name: "Code Your Future", url: "https://codeyourfuture.io/" }, { name: "Generation UK", url: "https://uk.generation.org/" }, { name: "Skills Bootcamps (GOV.UK)", url: "https://www.gov.uk/guidance/find-a-skills-bootcamp" }, { name: "BCS — Chartered Institute for IT", url: "https://www.bcs.org/" }] },
  { icon: "🌱", content: { en: { title: "Green Energy & Retrofit", salary: "£28K–£65K+" } }, tags: ["Heat Pumps", "Solar", "EV Charging"], steps: { en: ["The UK has legally committed to net zero by 2050. Warm Homes Plan, Great British Insulation Scheme, and Heat Pump Target (600K/year by 2028) create hundreds of thousands of new jobs. Demand for trained installers far exceeds supply.", "Entry route — no experience needed: start as a general operative or labourer on retrofit projects (loft insulation, external wall insulation, cavity wall fill). These are often agency roles paying £13–£15/hr with no qualifications required.", "Heat pump installer: the highest-earning green trade role. Training: MCS-accredited heat pump course (5–10 days, ~£1,500 — but Skills Bootcamps fund this fully). MCS certification is the UK industry standard — required to install on any government-funded scheme. Earning potential: £35K–£65K.", "Solar PV installer: fast-growing and high demand. Training: Level 3 Award in the Installation and Maintenance of Solar Photovoltaic Systems (5 days, ~£1,000 — Skills Bootcamp funded). MCS or NAPIT/NICEIC accreditation required to earn government-backed work.", "EV (electric vehicle) charging installer: rapid growth sector. Course: City & Guilds 2919-01 EV Charging Equipment Installation (1–2 days for qualified electricians, 5 days otherwise). OZEV authorisation needed for workplace and public installs. Salaries: £30K–£50K.", "If you have a background in plumbing, electrical, or HVAC (heating, ventilation, air conditioning) — your overseas skills are directly transferable. Get UK equivalency checked via SkillsRoads or directly with NAPIT/NICEIC.", "Retrofit Coordinator: a new desk-based role overseeing the planning and quality assurance of whole-house energy upgrades. PAS 2030/2035 Retrofit Coordinator qualification (5 days, ~£1,500 — often funded by councils or large contractors).", "Target employers: Mitie, Kier, Wates, Sero, Warmworks, Octopus Energy, local councils, housing associations. The social housing sector is the biggest source of green retrofit work in the UK right now.", "Salary progression: operative £26K–£32K → qualified installer £32K–£45K → MCS-accredited contractor owner £45K–£65K+. Government apprenticeship levy means many employers will fund your training while paying a salary."] }, links: [{ name: "Find Skills Bootcamp (GOV.UK)", url: "https://www.gov.uk/guidance/find-a-skills-bootcamp" }, { name: "MCS Certification (heat pumps & solar)", url: "https://mcscertified.com/" }, { name: "CITB green construction training", url: "https://www.citb.co.uk/courses-and-qualifications/green-construction/" }, { name: "Microgeneration Certification Scheme", url: "https://mcscertified.com/become-mcs-certified/" }, { name: "EV Charging (OZEV)", url: "https://www.gov.uk/guidance/office-for-zero-emission-vehicles" }] },
  { icon: "💷", content: { en: { title: "Finance & Accountancy", salary: "£25K–£70K+" } }, tags: ["ACCA", "CIMA", "AAT"], steps: { en: ["Start with AAT (Association of Accounting Technicians): AAT Level 2 is FREE if you earn under £25,734 or are on Universal Credit — this is the standard UK entry qualification for bookkeeping and accounts roles. Takes 6–12 months part-time.", "ACCA Refugee Bursary: the ACCA (Association of Chartered Certified Accountants) specifically funds exam fees for refugees. Apply via their website — covers registration and first exam sittings. ACCA is the most internationally recognised accounting qualification in the UK.", "CIMA (Chartered Institute of Management Accountants): strong in commercial and business settings. CIMA offers a refugee support programme. Start at Operational level if you have overseas finance experience.", "Study providers: Kaplan Financial and BPP are the UK's two largest ACCA/CIMA/AAT providers. Both have refugee and hardship bursaries — email them directly before paying any fees.", "Entry-level roles: Accounts Assistant, Purchase Ledger Clerk, Bookkeeper, Payroll Administrator. These typically pay £22K–£28K and do not require a UK qualification to start — your overseas experience gets you in.", "NHS Finance: the NHS is one of the UK's largest employers of finance staff. NHS Finance Trainee Scheme is specifically designed for people who want to qualify in finance while working. Many NHS trusts run refugee employment schemes.", "Big 4 and refugee programmes: KPMG, Deloitte, and PwC all run active refugee employment partnerships. These are competitive, but worth applying to — they fast-track strong candidates into paid roles while funding qualifications.", "Your overseas finance degree and experience: get UK ENIC recognition (£49) so UK employers can verify your qualifications. If you have several years of finance or accounting experience, you may qualify for ACCA or CIMA exemptions — contact each body's international routes team.", "Salary progression: Accounts Assistant £22K–£28K → ACCA/CIMA part-qualified £28K–£38K → Qualified Accountant £38K–£55K → Finance Manager / FD £55K–£70K+."] }, links: [{ name: "ACCA — refugee bursary", url: "https://www.accaglobal.com/uk/en/student/exam-entry-and-administration/acca-journey/refugee-support.html" }, { name: "AAT — accounting qualifications", url: "https://www.aat.org.uk/" }, { name: "CIMA — management accounting", url: "https://www.cimaglobal.com/" }, { name: "Kaplan Financial", url: "https://kaplan.co.uk/courses/acca" }, { name: "NHS Finance trainee scheme", url: "https://www.healthfinancenet.co.uk/career/trainee-scheme/" }] },
  { icon: "📊", content: { en: { title: "Project & Business Management", salary: "£30K–£80K+" } }, tags: ["APM", "CMI", "MBA"], steps: { en: [
    "An overseas MBA combined with an engineering, construction, or technical degree is exceptionally powerful in the UK — construction, infrastructure, energy, and digital are among the UK's largest growth sectors and all have a persistent shortage of people who can manage both the technical and commercial dimensions. This combination puts you above standard graduate PM hires.",
    "Get UK ENIC recognition of your MBA (£49 at enic.org.uk). Refugees without original documents: email refugee@ecctis.com. An ENIC-verified MBA from a recognised institution carries real weight with UK employers and is required for some qualification-credit exemptions.",
    "APM (Association for Project Management) is the UK's primary professional body for project managers. APM runs a specific refugee support and mentoring programme — contact membership@apm.org.uk. The APM PMQ (Project Management Qualification) is the UK benchmark qualification, comparable to PRINCE2 Practitioner.",
    "If you have an engineering background, target Construction Project Management or Infrastructure Project Management specifically — roles that pay £35K–£55K at entry level and £60K–£80K+ at senior level. Firms like Turner & Townsend, Faithful+Gould, Gleeds, and AECOM specifically need PMs who understand engineering. Your overseas infrastructure projects are directly relevant — describe them using UK frameworks (RIBA stages, NEC contracts, CDM regulations).",
    "CMI (Chartered Management Institute) Level 7 qualification maps directly to MBA content and is the UK business management gold standard. A Chartered Manager Degree Apprenticeship delivers a CMI Level 6 or 7 while you earn a salary — offered by BAM, Costain, Morgan Sindall, and NHS. Competitive but very achievable with an MBA background.",
    "PMP (Project Management Professional) is globally recognised. Your management experience may qualify you to sit the exam directly without additional training — check eligibility at pmi.org. Exam cost ~£300. Strong combined signal with APM PMQ.",
    "PRINCE2 Foundation + Practitioner (combined ~£500 via Axelos) is the standard in UK government, NHS, and public sector projects. Combined with APM PMQ, these two make you highly competitive for public-sector PM roles at councils, NHS trusts, and government agencies.",
    "Target employers who value engineering + MBA combination: Turner & Townsend, Faithful+Gould, Gleeds, Arcadis, AECOM, WSP, Atkins, Mott MacDonald, and large contractors (Costain, Kier, BAM, Skanska). Also: National Grid, Anglian Water, Network Rail, HS2, Environment Agency, NHS Estates, and large councils with capital programmes.",
    "Salary progression: Project Coordinator/Engineer £32K–£45K → Project Manager £45K–£65K → Senior/Programme Manager £65K–£82K → Director £80K–£110K. Engineering background accelerates progression to PM grade within 12–24 months of UK experience."
  ] }, links: [
    { name: "APM (project management)", url: "https://www.apm.org.uk/" },
    { name: "CMI (management institute)", url: "https://www.managers.org.uk/" },
    { name: "UK ENIC (degree recognition)", url: "https://www.enic.org.uk/Qualifications/SOC/Default.aspx" },
    { name: "Find a degree apprenticeship", url: "https://www.findapprenticeship.service.gov.uk/" },
    { name: "PMP Certification (PMI)", url: "https://www.pmi.org/certifications/project-management-pmp" },
  ] },
  { icon: "🎓", content: { en: { title: "Teaching (Qualified Teacher Status)", salary: "£30K–£50K+" } }, tags: ["QTS", "Overseas teachers welcome", "Shortage subjects"], steps: { en: ["Overseas Trained Teachers (OTTs) can gain UK Qualified Teacher Status (QTS) through the assessment-only route — no retraining needed. You submit evidence of your teaching experience and subject knowledge. The process takes 3–12 months.", "Apply for QTS via the Teaching Regulation Agency (TRA) at gov.uk/check-qualified-teacher-status. You need a degree (any subject), an overseas teaching qualification, and at least 2 years of experience. Document translation may be needed.", "Refugees without original qualification documents: contact your local refugee support charity or the Refugee Employment Network — they can help you obtain statutory declarations as supporting evidence.", "Shortage subjects (highest bursaries and fastest hiring): Maths, Physics, Computing, Modern Foreign Languages, Chemistry, and Design & Technology. Training bursaries of £10,000–£28,000 are available for these subjects if you need to retrain.", "School Direct (Salaried): earn a salary from day one while training in a school. This route is competitive but highly valued for experienced overseas teachers. Apply via UCAS Teacher Training.", "Supply teaching agencies (Hays Education, Protocol Education, Teaching Personnel) offer flexible day-to-day work while you pursue permanent roles — a practical way to build UK classroom experience immediately.", "Multilingual teachers are highly sought-after. Schools with large Arabic, Somali, Urdu, or Pashto-speaking communities actively recruit bilingual TAs and teachers. Your language is a genuine asset.", "Breaking Barriers run a programme specifically for refugee teachers — career assessment, CV support, and employer introductions to schools with multilingual pupil populations.", "Salary: unqualified teacher £22K–£28K → NQT (newly qualified) £30K → mid-career £38K–£43K → senior leader £50K+. London weighting adds £3K–£7K on top."] }, links: [{ name: "Check/apply for QTS (GOV.UK)", url: "https://www.gov.uk/check-qualified-teacher-status" }, { name: "Find teacher training (GOV.UK)", url: "https://www.gov.uk/find-postgraduate-teacher-training-courses" }, { name: "Teaching bursaries (GOV.UK)", url: "https://getintoteaching.education.gov.uk/funding-and-support/scholarships-and-bursaries" }, { name: "Breaking Barriers — refugee teachers", url: "https://breaking-barriers.co.uk/refugee-support/employment/" }] },
  { icon: "🏗", content: { en: { title: "Civil Engineering", salary: "£28K–£80K+" } }, tags: ["CEng", "CSCS Blue Card", "ICE"], steps: { en: [
    "Get UK ENIC Statement of Comparability for your engineering degree — £49 at enic.org.uk. If you are a refugee without original documents, email refugee@ecctis.com — UK ENIC runs a waived or reduced-cost assessment specifically for refugees. Your BSc Civil Engineering from a recognised university (including Addis Ababa University and other African institutions) maps to a UK BEng Honours equivalent.",
    "Contact ICE (Institution of Civil Engineers) Refugee Support — this is your most valuable first action after receiving refugee status. ICE pairs you with a UK-based chartered civil engineer for free mentoring, CV review, and employer introductions. Email: refugee@ice.org.uk. Do this on Day 1.",
    "Get your CSCS Blue Card (Graduate Card) — not the Green Labourer Card. A civil engineering degree qualifies you for the Blue Card, which gives you site access at graduate/technician grade. Apply via cscs.uk.com after having your degree verified by UK ENIC. The CITB Health & Safety test (£22.50) is required first.",
    "Apply for Breaking Barriers 'Built Environment' track immediately after refugee status. They run structured employer introduction programmes for refugee engineers and surveyors, with partnerships at Atkins, Mott MacDonald, Skanska, Kier, and council engineering teams.",
    "Target entry-level professional roles — NOT labouring roles: Graduate Civil Engineer, Site Engineer, Engineering Technician, BIM/CAD Technician, AutoCAD Drafter, Survey Technician. Your degree is your entry ticket. Typical starting salary: £28K–£38K. Describe your overseas projects using UK quantity terms (e.g. RIBA stages, Eurocode, Health & Safety at Work Act).",
    "If you also hold an MBA or management qualification: target Construction Project Management specifically. This is a high-demand, high-pay niche that combines civil engineering technical knowledge with management — a rare combination. Roles: Project Engineer, Assistant PM, Commercial Manager, Design Manager. These roles pay £35K–£55K at entry level.",
    "Register with the Engineering Council at EngTech level as soon as you start your first UK role. Your overseas degree and experience count toward chartership. Target: EngTech (immediate) → IEng within 12–24 months of UK experience → CEng MICE within 3–5 years. ICE is your professional home.",
    "RefuAid interest-free professional loans (up to £10,000): apply after your positive asylum decision at refuaid.org. Loans cover ICE membership fees, UK ENIC assessment, CPD courses, software licences (AutoCAD, Revit, Civil 3D, Primavera), interview clothing, and chartership assessment costs.",
    "Target employers in civil and infrastructure: Atkins (SNC-Lavalin), Arup, Mott MacDonald, Jacobs, Stantec, WSP, Amey, Costain, Kier, Balfour Beatty, Skanska, Morgan Sindall, AtkinsRéalis, Turner & Townsend — and public-sector clients: Network Rail, National Highways, Environment Agency, Transport for London, HS2, Anglian Water, local councils (Norfolk CC, Norwich CC). All run graduate/experienced hire programmes.",
    "Salary progression: Engineering Technician/Site Engineer £28K–£38K → Design/Senior Engineer IEng £38K–£55K → Chartered Civil Engineer CEng MICE £55K–£80K+. The combination of overseas infrastructure experience + UK chartership = premium salary."
  ] }, links: [
    { name: "ICE Refugee Support", url: "https://www.ice.org.uk/about-ice/what-we-do/social-mobility/refugee-support/" },
    { name: "UK ENIC (degree recognition)", url: "https://www.enic.org.uk/Qualifications/SOC/Default.aspx" },
    { name: "Engineering Council (UK)", url: "https://www.engc.org.uk" },
    { name: "New Civil Engineer Jobs", url: "https://www.newcivilengineer.com/jobs/" },
    { name: "Breaking Barriers (refugee employment)", url: "https://breaking-barriers.co.uk/refugee-support/reaccreditation/" },
    { name: "RefuAid interest-free loans", url: "https://www.refuaid.org" },
  ] },
  { icon: "🏘", content: { en: { title: "Property Valuation & Surveying", salary: "£35K–£80K+" } }, tags: ["RICS", "MRICS", "APC"], steps: { en: [
    "Your overseas valuation experience — mortgage security valuations, market value reports, development appraisals, and commercial valuations — directly maps to UK practice. The methodology is almost identical to the RICS Red Book (RICS Valuation — Global Standards). Many African development banks and commercial lenders already follow RICS-derived valuation methodology. You are not starting from zero.",
    "Contact RICS (Royal Institution of Chartered Surveyors) at international@rics.org on Day 1 — explain your qualifications and years of experience and ask for a pre-assessment conversation about your APC route. This call is free and shapes everything. Do it before registering or paying any fees.",
    "For 5+ years of substantive valuation experience: apply for the RICS Senior Professional Assessment (SPA) route. This bypasses the standard 24-month APC structured training requirement. With a strong evidence portfolio of comparable analysis, Red Book-style reports, and professional development, SPA is achievable within 12–18 months of starting the process.",
    "UK ENIC degree recognition (£49): get a Statement of Comparability for your property, business, engineering, or management degree. Refugees without originals: email refugee@ecctis.com. RICS requires formal academic equivalence during the APC application process.",
    "Register as RICS Student or Associate (AssocRICS) as soon as possible. AssocRICS is achievable with your background within 6–12 months and lets you market yourself as 'RICS-registered' to employers. This is a meaningful CV signal — RICS is the only globally recognised property qualification.",
    "Key UK valuation skills to update: RICS Red Book Global Standards (2022 edition — free on rics.org), comparative method, income approach/yield methodology, residual (developer's) method, and AVMs (automated valuation models) used by mortgage lenders. Your existing professional knowledge covers most of this — the gap is UK-specific market terminology and planning law basics.",
    "Lender-panel valuations are a high-volume UK niche: e.surv, Countrywide Surveying Services (part of Connells), LSL Property Services, and Nationwide Surveying Services employ large numbers of residential mortgage valuers. These firms are used to hiring internationally experienced surveyors and will support your RICS APC.",
    "Breaking Barriers 'Built Environment' track: apply for their employer introduction programme. They have active partnerships with major surveying and property consultancy firms.",
    "RefuAid interest-free loans (up to £10,000): apply at refuaid.org after your positive decision. Can fund RICS registration fees, APC assessment costs, professional indemnity insurance (needed for self-employed valuation work), and UK-specific training.",
    "Salary: Valuation Assistant/AssocRICS £30K–£40K → MRICS Valuer £45K–£65K → Senior Registered Valuer / Director £65K–£100K+. Commercial valuation specialists (investment, development, infrastructure) earn significantly more."
  ] }, links: [
    { name: "RICS — routes to membership", url: "https://www.rics.org/surveying-profession/join-rics/" },
    { name: "RICS Senior Professional APC", url: "https://www.rics.org/surveying-profession/join-rics/assessment-of-professional-competence-apc/" },
    { name: "RICS International routes", url: "https://www.rics.org/surveying-profession/join-rics/international-routes-to-membership/" },
    { name: "UK ENIC (degree recognition)", url: "https://www.enic.org.uk/Qualifications/SOC/Default.aspx" },
    { name: "RICS Job Board", url: "https://jobs.rics.org/" },
    { name: "Breaking Barriers (refugee employment)", url: "https://breaking-barriers.co.uk/refugee-support/reaccreditation/" },
    { name: "RefuAid interest-free loans", url: "https://www.refuaid.org" },
  ] },
]
// ─── Stable string IDs for Careers (order matches array above) ──
const CAREER_IDS = [
  'healthcare', 'social-work', 'translation', 'tech-digital', 'green-energy', 'finance', 'project-management', 'teaching', 'civil-engineering', 'property-valuation'
]
CAREER_IDS.forEach((id, i) => { CAREERS[i].id = id })
export const CAREER_MAP = Object.fromEntries(CAREERS.map(c => [c.id, c]))